// DApp Smart Contract Interaction Module
// Uses ethers.js for building and sending transactions securely

const { ethers } = require('ethers');

// Configuration
const CONFIG = {
  MAX_GAS_LIMIT: 500000n,
  MIN_GAS_LIMIT: 21000n,
  MAX_VALUE_ETH: '100',
  SUPPORTED_NETWORKS: {
    1: 'mainnet',
    5: 'goerli',
    11155111: 'sepolia',
    137: 'polygon',
  },
  TX_TIMEOUT_MS: 120000,
  MAX_RETRIES: 3,
};

// ABI Registry - whitelisted contract ABIs
const ABI_REGISTRY = new Map();

// Whitelisted contract addresses per network
const WHITELISTED_CONTRACTS = new Map();

/**
 * Input validation utilities
 */
class InputValidator {
  static isValidAddress(address) {
    try {
      return ethers.isAddress(address);
    } catch {
      return false;
    }
  }

  static sanitizeString(input) {
    if (typeof input !== 'string') {
      throw new Error('Input must be a string');
    }
    // Remove any potentially dangerous characters, allow only alphanumeric, hyphens, underscores
    return input.replace(/[^a-zA-Z0-9_\-\.]/g, '');
  }

  static validateFunctionName(name) {
    const sanitized = this.sanitizeString(name);
    // Function names should be valid Solidity identifiers
    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(sanitized)) {
      throw new Error(`Invalid function name: ${sanitized}`);
    }
    return sanitized;
  }

  static validateUint256(value) {
    try {
      const bn = BigInt(value);
      if (bn < 0n) {
        throw new Error('Value must be non-negative');
      }
      if (bn > 2n ** 256n - 1n) {
        throw new Error('Value exceeds uint256 max');
      }
      return bn;
    } catch (e) {
      if (e.message.includes('Value must be') || e.message.includes('Value exceeds')) {
        throw e;
      }
      throw new Error('Invalid uint256 value');
    }
  }

  static validateEthValue(valueInEth) {
    const parsed = parseFloat(valueInEth);
    if (isNaN(parsed) || parsed < 0) {
      throw new Error('Invalid ETH value');
    }
    if (parsed > parseFloat(CONFIG.MAX_VALUE_ETH)) {
      throw new Error(`ETH value exceeds maximum of ${CONFIG.MAX_VALUE_ETH}`);
    }
    return ethers.parseEther(valueInEth.toString());
  }

  static validateGasLimit(gasLimit) {
    const bn = BigInt(gasLimit);
    if (bn < CONFIG.MIN_GAS_LIMIT) {
      throw new Error(`Gas limit below minimum of ${CONFIG.MIN_GAS_LIMIT}`);
    }
    if (bn > CONFIG.MAX_GAS_LIMIT) {
      throw new Error(`Gas limit exceeds maximum of ${CONFIG.MAX_GAS_LIMIT}`);
    }
    return bn;
  }

  static validateFunctionArgs(args, abiInputs) {
    if (!Array.isArray(args)) {
      throw new Error('Arguments must be an array');
    }
    if (args.length !== abiInputs.length) {
      throw new Error(`Expected ${abiInputs.length} arguments, got ${args.length}`);
    }

    return args.map((arg, index) => {
      const expectedType = abiInputs[index].type;
      return this.validateArgByType(arg, expectedType);
    });
  }

  static validateArgByType(arg, solidityType) {
    if (solidityType === 'address') {
      if (!this.isValidAddress(arg)) {
        throw new Error(`Invalid address argument: ${arg}`);
      }
      return ethers.getAddress(arg); // Checksummed address
    }

    if (solidityType.startsWith('uint')) {
      return this.validateUint256(arg).toString();
    }

    if (solidityType.startsWith('int')) {
      const bn = BigInt(arg);
      const bits = parseInt(solidityType.replace('int', '') || '256');
      const max = 2n ** BigInt(bits - 1) - 1n;
      const min = -(2n ** BigInt(bits - 1));
      if (bn > max || bn < min) {
        throw new Error(`Value out of range for ${solidityType}`);
      }
      return bn.toString();
    }

    if (solidityType === 'bool') {
      if (typeof arg === 'boolean') return arg;
      if (arg === 'true') return true;
      if (arg === 'false') return false;
      throw new Error('Invalid boolean argument');
    }

    if (solidityType === 'string') {
      if (typeof arg !== 'string') {
        throw new Error('Expected string argument');
      }
      if (arg.length > 10000) {
        throw new Error('String argument too long');
      }
      return arg;
    }

    if (solidityType.startsWith('bytes')) {
      if (!ethers.isBytesLike(arg)) {
        throw new Error(`Invalid bytes argument for type ${solidityType}`);
      }
      return arg;
    }

    // For array types, validate recursively
    if (solidityType.endsWith('[]')) {
      if (!Array.isArray(arg)) {
        throw new Error(`Expected array for type ${solidityType}`);
      }
      const baseType = solidityType.slice(0, -2);
      return arg.map(item => this.validateArgByType(item, baseType));
    }

    return arg;
  }
}

/**
 * Rate limiter to prevent transaction spam
 */
class RateLimiter {
  constructor(maxRequests = 5, windowMs = 60000) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = [];
  }

  canProceed() {
    const now = Date.now();
    this.requests = this.requests.filter(t => now - t < this.windowMs);
    if (this.requests.length >= this.maxRequests) {
      return false;
    }
    this.requests.push(now);
    return true;
  }
}

/**
 * Transaction logger for audit trail
 */
class TransactionLogger {
  constructor() {
    this.logs = [];
  }

  log(entry) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      ...entry,
    };
    this.logs.push(logEntry);
    console.log('[TX LOG]', JSON.stringify(logEntry, null, 2));
  }

  getRecentLogs(count = 10) {
    return this.logs.slice(-count);
  }
}

/**
 * Secure DApp Contract Interaction Manager
 */
class DAppContractManager {
  constructor() {
    this.provider = null;
    this.signer = null;
    this.contracts = new Map();
    this.rateLimiter = new RateLimiter(5, 60000);
    this.logger = new TransactionLogger();
    this.pendingTransactions = new Map();
    this.initialized = false;
  }

  /**
   * Initialize the DApp with wallet connection
   * Uses the wallet's built-in signing mechanism (MetaMask, etc.)
   * Never handles or stores private keys directly
   */
  async initialize() {
    if (typeof window === 'undefined' || !window.ethereum) {
      throw new Error('No Web3 wallet detected. Please install MetaMask or a compatible wallet.');
    }

    try {
      // Request account access through the wallet provider
      const accounts = await window.ethereum.request({
        method: 'eth_requestAccounts',
      });

      if (!accounts || accounts.length === 0) {
        throw new Error('No accounts available. Please unlock your wallet.');
      }

      // Use BrowserProvider which delegates signing to the wallet
      this.provider = new ethers.BrowserProvider(window.ethereum);
      this.signer = await this.provider.getSigner();

      const network = await this.provider.getNetwork();
      const chainId = Number(network.chainId);

      if (!CONFIG.SUPPORTED_NETWORKS[chainId]) {
        throw new Error(
          `Unsupported network (chainId: ${chainId}). Supported: ${Object.values(CONFIG.SUPPORTED_NETWORKS).join(', ')}`
        );
      }

      // Listen for account and network changes
      window.ethereum.on('accountsChanged', (accounts) => {
        this.logger.log({ event: 'accountsChanged', accounts: accounts.map(a => a.substring(0, 10) + '...') });
        this.handleAccountChange(accounts);
      });

      window.ethereum.on('chainChanged', (chainId) => {
        this.logger.log({ event: 'chainChanged', chainId });
        // Reload on chain change as recommended by MetaMask
        window.location.reload();
      });

      this.initialized = true;
      this.logger.log({
        event: 'initialized',
        network: CONFIG.SUPPORTED_NETWORKS[chainId],
        chainId,
        account: (await this.signer.getAddress()).substring(0, 10) + '...',
      });

      return {
        address: await this.signer.getAddress(),
        network: CONFIG.SUPPORTED_NETWORKS[chainId],
        chainId,
      };
    } catch (error) {
      this.logger.log({ event: 'initError', error: error.message });
      throw new Error(`Failed to initialize DApp: ${error.message}`);
    }
  }

  /**
   * Handle account changes from wallet
   */
  async handleAccountChange(accounts) {
    if (accounts.length === 0) {
      this.signer = null;
      this.initialized = false;
      throw new Error('Wallet disconnected');
    }
    this.signer = await this.provider.getSigner();
  }

  /**
   * Register a contract ABI in the whitelist
   */
  registerContractABI(name, abi) {
    const sanitizedName = InputValidator.sanitizeString(name);
    if (!Array.isArray(abi)) {
      throw new Error('ABI must be an array');
    }
    // Validate ABI structure
    for (const item of abi) {
      if (item.type === 'function' && typeof item.name !== 'string') {
        throw new Error('Invalid ABI: function entries must have a name');
      }
    }
    ABI_REGISTRY.set(sanitizedName, abi);
    this.logger.log({ event: 'abiRegistered', name: sanitizedName });
  }

  /**
   * Whitelist a contract address for a specific network
   */
  whitelistContract(chainId, address, abiName) {
    if (!InputValidator.isValidAddress(address)) {
      throw new Error('Invalid contract address');
    }
    const checksumAddress = ethers.getAddress(address);
    const sanitizedAbiName = InputValidator.sanitizeString(abiName);

    if (!ABI_REGISTRY.has(sanitizedAbiName)) {
      throw new Error(`ABI "${sanitizedAbiName}" not registered`);
    }

    if (!WHITELISTED_CONTRACTS.has(chainId)) {
      WHITELISTED_CONTRACTS.set(chainId, new Map());
    }
    WHITELISTED_CONTRACTS.get(chainId).set(checksumAddress, sanitizedAbiName);

    this.logger.log({
      event: 'contractWhitelisted',
      chainId,
      address: checksumAddress,
      abiName: sanitizedAbiName,
    });
  }

  /**
   * Get or create a contract instance (only for whitelisted contracts)
   */
  async getContract(contractAddress) {
    this.ensureInitialized();

    if (!InputValidator.isValidAddress(contractAddress)) {
      throw new Error('Invalid contract address');
    }

    const checksumAddress = ethers.getAddress(contractAddress);
    const network = await this.provider.getNetwork();
    const chainId = Number(network.chainId);

    // Check whitelist
    const networkContracts = WHITELISTED_CONTRACTS.get(chainId);
    if (!networkContracts || !networkContracts.has(checksumAddress)) {
      throw new Error(
        `Contract ${checksumAddress} is not whitelisted on network ${chainId}`
      );
    }

    const cacheKey = `${chainId}-${checksumAddress}`;
    if (this.contracts.has(cacheKey)) {
      return this.contracts.get(cacheKey);
    }

    const abiName = networkContracts.get(checksumAddress);
    const abi = ABI_REGISTRY.get(abiName);

    if (!abi) {
      throw new Error(`ABI "${abiName}" not found in registry`);
    }

    const contract = new ethers.Contract(checksumAddress, abi, this.signer);
    this.contracts.set(cacheKey, contract);

    return contract;
  }

  /**
   * Build a transaction for a contract call with full validation
   */
  async buildTransaction(params) {
    this.ensureInitialized();

    const {
      contractAddress,
      functionName,
      args = [],
      value = '0',
      gasLimit,
    } = params;

    // Validate contract address and get contract
    const contract = await this.getContract(contractAddress);

    // Validate function name
    const sanitizedFunctionName = InputValidator.validateFunctionName(functionName);

    // Verify function exists in the contract ABI
    const contractFunction = contract.interface.getFunction(sanitizedFunctionName);
    if (!contractFunction) {
      throw new Error(`Function "${sanitizedFunctionName}" not found in contract ABI`);
    }

    // Validate arguments against ABI
    const validatedArgs = InputValidator.validateFunctionArgs(args, contractFunction.inputs);

    // Validate ETH value
    const validatedValue = InputValidator.validateEthValue(value);

    // If function is not payable, ensure no value is sent
    if (contractFunction.stateMutability !== 'payable' && validatedValue > 0n) {
      throw new Error(`Function "${sanitizedFunctionName}" is not payable but value was provided`);
    }

    // Build the transaction object
    const txRequest = await contract[sanitizedFunctionName].populateTransaction(...validatedArgs);

    // Set value
    txRequest.value = validatedValue;

    // Set gas limit
    if (gasLimit) {
      txRequest.gasLimit = InputValidator.validateGasLimit(gasLimit);
    } else {
      // Estimate gas with a safety margin
      try {
        const estimatedGas = await this.provider.estimateGas({
          ...txRequest,
          from: await this.signer.getAddress(),
        });
        const gasWithMargin = (estimatedGas * 120n) / 100n; // 20% margin
        txRequest.gasLimit = gasWithMargin > CONFIG.MAX_GAS_LIMIT ? CONFIG.MAX_GAS_LIMIT : gasWithMargin;
      } catch (error) {
        throw new Error(`Gas estimation failed: ${error.message}. The transaction may revert.`);
      }
    }

    this.logger.log({
      event: 'transactionBuilt',
      to: txRequest.to,
      function: sanitizedFunctionName,
      value: ethers.formatEther(validatedValue),
      gasLimit: txRequest.gasLimit?.toString(),
    });

    return txRequest;
  }

  /**
   * Send a transaction with rate limiting and confirmation tracking
   * Signing is delegated entirely to the connected wallet (MetaMask, etc.)
   */
  async sendTransaction(params) {
    this.ensureInitialized();

    // Rate limiting
    if (!this.rateLimiter.canProceed()) {
      throw new Error('Rate limit exceeded. Please wait before sending another transaction.');
    }

    // Build the transaction
    const txRequest = await this.buildTransaction(params);

    // Display transaction details for user confirmation
    const txSummary = {
      to: txRequest.to,
      function: params.functionName,
      args: params.args,
      value: ethers.formatEther(txRequest.value || 0n),
      gasLimit: txRequest.gasLimit?.toString(),
    };

    this.logger.log({ event: 'sendingTransaction', summary: txSummary });

    try {
      // The signer.sendTransaction delegates signing to the wallet provider
      // The user will see a confirmation popup in their wallet (e.g., MetaMask)
      // No private keys are ever handled in this code
      const tx = await this.signer.sendTransaction(txRequest);

      this.logger.log({
        event: 'transactionSent',
        hash: tx.hash,
        nonce: tx.nonce,
      });

      // Track pending transaction
      this.pendingTransactions.set(tx.hash, {
        ...txSummary,
        hash: tx.hash,
        timestamp: Date.now(),
        status: 'pending',
      });

      return {
        hash: tx.hash,
        summary: txSummary,
        wait: () => this.waitForConfirmation(tx),
      };
    } catch (error) {
      if (error.code === 'ACTION_REJECTED' || error.code === 4001) {
        this.logger.log({ event: 'transactionRejected' });
        throw new Error('Transaction was rejected by the user');
      }
      this.logger.log({ event: 'transactionError', error: error.message });
      throw new Error(`Failed to send transaction: ${error.message}`);
    }
  }

  /**
   * Wait for transaction confirmation with timeout
   */
  async waitForConfirmation(tx, confirmations = 1) {
    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => reject(new Error('Transaction confirmation timeout')), CONFIG.TX_TIMEOUT_MS);
    });

    try {
      const receipt = await Promise.race([
        tx.wait(confirmations),
        timeoutPromise,
      ]);

      const status = receipt.status === 1 ? 'confirmed' : 'failed';

      if (this.pendingTransactions.has(tx.hash)) {
        this.pendingTransactions.get(tx.hash).status = status;
      }

      this.logger.log({
        event: 'transactionConfirmed',
        hash: tx.hash,
        status,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
      });

      return {
        status,
        hash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        events: receipt.logs,
      };
    } catch (error) {
      if (this.pendingTransactions.has(tx.hash)) {
        this.pendingTransactions.get(tx.hash).status = 'error';
      }
      throw error;
    }
  }

  /**
   * Execute a read-only (view/pure) contract call
   */
  async callContractFunction(params) {
    this.ensureInitialized();

    const { contractAddress, functionName, args = [] } = params;

    const contract = await this.getContract(contractAddress);
    const sanitizedFunctionName = InputValidator.validateFunctionName(functionName);

    const contractFunction = contract.interface.getFunction(sanitizedFunctionName);
    if (!contractFunction) {
      throw new Error(`Function "${sanitizedFunctionName}" not found in contract ABI`);
    }

    // Verify it's a view/pure function
    if (contractFunction.stateMutability !== 'view' && contractFunction.stateMutability !== 'pure') {
      throw new Error(
        `Function "${sanitizedFunctionName}" is not a view/pure function. Use sendTransaction instead.`
      );
    }

    const validatedArgs = InputValidator.validateFunctionArgs(args, contractFunction.inputs);

    try {
      const result = await contract[sanitizedFunctionName](...validatedArgs);

      this.logger.log({
        event: 'contractCall',
        contractAddress,
        function: sanitizedFunctionName,
        success: true,
      });

      return result;
    } catch (error) {
      this.logger.log({
        event: 'contractCallError',
        contractAddress,
        function: sanitizedFunctionName,
        error: error.message,
      });
      throw new Error(`Contract call failed: ${error.message}`);
    }
  }

  /**
   * Get the current account balance
   */
  async getBalance() {
    this.ensureInitialized();
    const address = await this.signer.getAddress();
    const balance = await this.provider.getBalance(address);
    return {
      wei: balance.toString(),
      eth: ethers.formatEther(balance),
    };
  }

  /**
   * Get pending transactions
   */
  getPendingTransactions() {
    return Array.from(this.pendingTransactions.values()).filter(
      (tx) => tx.status === 'pending'
    );
  }

  /**
   * Get transaction history from logger
   */
  getTransactionHistory(count = 20) {
    return this.logger.getRecentLogs(count);
  }

  /**
   * Ensure the manager is initialized
   */
  ensureInitialized() {
    if (!this.initialized || !this.signer) {
      throw new Error('DApp not initialized. Call initialize() first.');
    }
  }

  /**
   * Disconnect and clean up
   */
  disconnect() {
    this.signer = null;
    this.provider = null;
    this.contracts.clear();
    this.initialized = false;
    this.logger.log({ event: 'disconnected' });
  }
}

